      <div v-if="lastSyncedAt" class="sync-banner">
        <div class="sync-banner-dot"></div>
        <div class="sync-banner-copy">
          <span class="sync-banner-title">已配置同步</span>
          <span class="sync-banner-sub">上次同步: {{ fmtDate(lastSyncedAt) }}</span>
