                <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><path d="M22 19a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h5l2 3h9a2 2 0 0 1 2 2z"/></svg>
              </span>
              <span class="sync-section-label">仓库信息</span>
            </div>
            <div class="sync-field-row">
              <label class="sync-field" style="flex:1.2">
                <span class="sync-field-label">用户名</span>
                <input v-model="form.owner" class="input" placeholder="如 nyhxiaoning" />
              </label>
              <label class="sync-field" style="flex:1.8">
