const emit = defineEmits(['close', 'saved'])

const showToken = ref(false)
const form = ref({ owner: '', repo: '', path: '', token: '' })
const hasConfig = ref(false)
const lastSyncedAt = ref('')

watch(() => props.open, async (val) => {
  showToken.value = false
  if (val && props.dramaId) {
    try {
      const res = await syncAPI.config(props.dramaId)
      if (res) {
        form.value = {
          owner: res.github_owner || '',
          repo: res.github_repo || '',
          path: res.github_path || '',
          token: '',
        }
        hasConfig.value = true
        lastSyncedAt.value = res.last_synced_at || ''
      } else {
        form.value = { owner: '', repo: '', path: 'data/drama-' + props.dramaId + '.json', token: '' }
        hasConfig.value = false
        lastSyncedAt.value = ''
      }
    } catch {}
  }
})

async function handleSave() {
  if (!form.value.owner || !form.value.repo || !form.value.path || !form.value.token) {
    toast.warning('请填写所有必填项')
    return
  }
  try {
    await syncAPI.saveConfig(props.dramaId, {
      github_owner: form.value.owner,
      github_repo: form.value.repo,
      github_path: form.value.path,
      github_token: form.value.token,
    })
    toast.success('GitHub 同步配置已保存')
    emit('saved')
    emit('close')
  } catch (e) {
    toast.error(e.message)
  }
}

async function handleClear() {
  try {
    await syncAPI.deleteConfig(props.dramaId)
    form.value = { owner: '', repo: '', path: 'data/drama-' + props.dramaId + '.json', token: '' }
    hasConfig.value = false
    lastSyncedAt.value = ''
    toast.success('同步配置已清除')
    emit('close')
  } catch (e) {
    toast.error(e.message)
  }
}

function fmtDate(s) {
  if (!s) return ''
  return new Date(s).toLocaleString('zh-CN')
}
</script>

