  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 10px;
  border: 1px solid rgba(27, 41, 64, 0.1);
  background: rgba(255,255,255,0.86);
  color: var(--text-2);
